#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int x, y, z, k;
    scanf("%d %d %d %d", &x, &y, &z, &k);

    int dim[3] = {x - 1, y - 1, z - 1};
    qsort(dim, 3, sizeof(int), compare);

    int answer[3] = {0, 0, 0};

    for (int i = 0; i < 3; i++) {
        int dimi = dim[i];
        if (dimi * (3 - i) <= k) {
            k -= dimi * (3 - i);
            for (int j = i; j < 3; j++) {
                answer[j] += dimi;
            }
            for (int j = 0; j < 3; j++) {
                dim[j] -= dimi;
            }
        } else {
            for (int j = i; j < 3; j++) {
                answer[j] += k / (3 - i);
            }
            for (int j = i; j < i + (k % (3 - i)); j++) {
                answer[j] += 1;
            }
            break;
        }
    }

    long long true_ans = 1;
    for (int i = 0; i < 3; i++) {
        true_ans *= (answer[i] + 1);
